  1→//! Stratum selection: explore functions at specific call graph depths.
  2→//!
  3→//! Supports single layers, ranges (inclusive), open-ended ranges, and negative
  4→//! indices (where -0 = max depth, -1 = second from top, etc.).
  5→//!
  6→//! Syntax examples:
  7→//! - `"0"` — layer 0 only (leaf functions)
  8→//! - `"0..3"` — layers 0 through 3 inclusive
  9→//! - `"3.."` — layer 3 and above
 10→//! - `"..3"` — layers 0 through 3
 11→//! - `"-0"` — top layer (entry points)
 12→//! - `"-2..-0"` — top 3 layers
 13→
 14→use std::ops::RangeInclusive;
 15→
 16→use crate::scan_orchestrator::ScanError;
 17→
 18→/// A parsed stratum specification.
 19→#[derive(Debug, Clone)]
 20→pub struct StratumSpec {
 21→    kind: SpecKind,
 22→}
 23→
 24→#[derive(Debug, Clone)]
 25→enum SpecKind {
 26→    /// A single layer index.
 27→    Single(LayerIndex),
 28→    /// An inclusive range of layers.
 29→    Range {
 30→        start: Option<LayerIndex>,
 31→        end: Option<LayerIndex>,
 32→    },
 33→}
 34→
 35→/// A layer index, possibly negative (counted from the top).
 36→#[derive(Debug, Clone, Copy)]
 37→struct LayerIndex {
 38→    /// The numeric value (always non-negative).
 39→    value: usize,
 40→    /// Whether this is a negative index (counted from max depth).
 41→    negative: bool,
 42→}
 43→
 44→impl LayerIndex {
 45→    /// Resolve this index to an absolute layer number given the max layer.
 46→    fn resolve(self, max_layer: usize) -> usize {
 47→        if self.negative {
 48→            // -0 = max_layer, -1 = max_layer - 1, etc.
 49→            max_layer.saturating_sub(self.value)
 50→        } else {
 51→            self.value
 52→        }
 53→    }
 54→}
 55→
 56→/// Parse a stratum specification string.
 57→///
 58→/// Accepted formats:
 59→/// - `"N"` or `"-N"` — single layer
 60→/// - `"A..B"` — inclusive range (A and B may be negative)
 61→/// - `"A.."` — open-ended range from A
 62→/// - `"..B"` — open-ended range to B
 63→pub fn parse_stratum_spec(s: &str) -> Result<StratumSpec, String> {
 64→    let s = s.trim();
 65→
 66→    if let Some((left, right)) = s.split_once("..") {
 67→        let start = if left.is_empty() {
 68→            None
 69→        } else {
 70→            Some(parse_layer_index(left)?)
 71→        };
 72→        let end = if right.is_empty() {
 73→            None
 74→        } else {
 75→            Some(parse_layer_index(right)?)
 76→        };
 77→        if start.is_none() && end.is_none() {
 78→            return Err("stratum range must have at least one bound: \"..\" is not valid".into());
 79→        }
 80→        Ok(StratumSpec {
 81→            kind: SpecKind::Range { start, end },
 82→        })
 83→    } else {
 84→        let idx = parse_layer_index(s)?;
 85→        Ok(StratumSpec {
 86→            kind: SpecKind::Single(idx),
 87→        })
 88→    }
 89→}
 90→
 91→fn parse_layer_index(s: &str) -> Result<LayerIndex, String> {
 92→    let s = s.trim();
 93→    if let Some(rest) = s.strip_prefix('-') {
 94→        let value: usize = rest
 95→            .parse()
 96→            .map_err(|_| format!("invalid layer index: {s}"))?;
 97→        Ok(LayerIndex {
 98→            value,
 99→            negative: true,
100→        })

100→        })
101→    } else {
102→        let value: usize = s
103→            .parse()
104→            .map_err(|_| format!("invalid layer index: {s}"))?;
105→        Ok(LayerIndex {
106→            value,
107→            negative: false,
108→        })
109→    }
110→}
111→
112→/// Resolve a stratum spec into an inclusive range of absolute layer indices.
113→///
114→/// Returns `Err(ScanError)` if the resolved range is empty or out of bounds.
115→pub fn resolve_range(
116→    spec: &StratumSpec,
117→    max_layer: usize,
118→) -> Result<RangeInclusive<usize>, ScanError> {
119→    let (start, end) = match &spec.kind {
120→        SpecKind::Single(idx) => {
121→            let resolved = idx.resolve(max_layer);
122→            (resolved, resolved)
123→        }
124→        SpecKind::Range { start, end } => {
125→            let s = start.map_or(0, |i| i.resolve(max_layer));
126→            let e = end.map_or(max_layer, |i| i.resolve(max_layer));
127→            (s, e)
128→        }
129→    };
130→
131→    // Clamp to valid range.
132→    let start = start.min(max_layer);
133→    let end = end.min(max_layer);
134→
135→    if start > end {
136→        return Err(ScanError::Stratum(format!(
137→            "resolved range {start}..={end} is empty (start > end after resolving negative indices)"
138→        )));
139→    }
140→
141→    Ok(start..=end)
142→}
143→
144→/// Filter layers to only those within the given range.
145→///
146→/// Returns `(original_layer_index, &functions)` pairs for layers in the range.
147→pub fn filter_layers<'a>(
148→    layers: &'a [Vec<String>],
149→    range: &RangeInclusive<usize>,
150→) -> Vec<(usize, &'a Vec<String>)> {
151→    layers
152→        .iter()
153→        .enumerate()
154→        .filter(|(idx, _)| range.contains(idx))
155→        .collect()
156→}
